#include <stdio.h>

#define MAX 100

int stack[MAX];
int top = -1;

// Function to push an element onto the stack
void push(int value)
{
    // Check for stack overflow
    // If overflow occurs, print: "Stack Overflow"
    if(top == MAX - 1)
    {
        printf("Stack Overflow\n");
        return;
    }

    top++;
    stack[top] = value;
}

// Function to pop an element from the stack
int pop()
{
    // Check for stack underflow
    // If underflow occurs, print: "Stack Underflow"
    if(top == -1)
    {
        printf("Stack Underflow\n");
        return -1;
    }

    int value = stack[top];
    top--;
    return value;
}

// Function to peek the top element
int peek()
{
    // Check if stack is empty
    // If empty, print: "Stack is Empty"
    if(top == -1)
    {
        printf("Stack is Empty\n");
        return -1;
    }

    return stack[top];
}

