const STACK_CAPACITY = 101;
let stackArray = new Array(STACK_CAPACITY);
let topIndex = -1;

function push(character) {
    if (isFull()) {
        console.log("Stack is full");
    } else {
        stackArray[++topIndex] = character;
    }
}

function pop() {
    if (isEmpty()) {
        console.log("Stack is empty");
        return null;
    } else {
        let character = stackArray[topIndex];
        topIndex--;
        return character;
    }
}

function isEmpty() {
    return topIndex === -1;
}

function isFull() {
    return topIndex >= STACK_CAPACITY - 1;
}

function reverseString(inputString) {
    const inputLength = inputString.length;

    for (let i = 0; i < inputLength; i++) {
        let currentChar = inputString[i];
        push(currentChar);
    }

    let reversedString = '';
    while (!isEmpty()) {
        reversedString += pop();
    }

    return reversedString;
}

